import React, { useState, useEffect } from 'react';
import { db } from '../firebase';
import { collection, onSnapshot, doc, updateDoc, deleteDoc } from 'firebase/firestore';
import { CheckCircle, Package, RefreshCcw, ArrowLeft, Utensils } from 'lucide-react';

function CanteenAdmin({ onBack }) {
  const [orders, setOrders] = useState([]);
  const [inventory, setInventory] = useState([]);

  useEffect(() => {
    // 1. Sync Live Orders (Tokens generated by students)
    const unsubOrders = onSnapshot(collection(db, "orders"), (snap) => {
      setOrders(snap.docs.map(d => ({ id: d.id, ...d.data() })));
    });

    // 2. Sync Inventory (Items on the shelf)
    const unsubInv = onSnapshot(collection(db, "canteen_items"), (snap) => {
      setInventory(snap.docs.map(d => ({ id: d.id, ...d.data() })));
    });

    return () => { unsubOrders(); unsubInv(); };
  }, []);

  const completeOrder = async (id) => {
    if (window.confirm("Is the food served? This will clear the token.")) {
      await deleteDoc(doc(db, "orders", id));
    }
  };

  const updateStock = async (id, newStock) => {
    if (newStock < 0) return;
    await updateDoc(doc(db, "canteen_items", id), { stock: parseInt(newStock) || 0 });
  };

  return (
    <div className="min-h-screen bg-[#050505] text-white p-6 md:p-10 font-sans selection:bg-indigo-500/30">
      
      {/* Header Section */}
      <div className="max-w-7xl mx-auto flex flex-col md:flex-row justify-between items-start md:items-center mb-10 gap-6">
        <div>
          <h1 className="text-4xl font-black tracking-tighter flex items-center gap-3">
            <Utensils className="text-orange-500 w-10 h-10" /> CANTEEN CONTROL
          </h1>
          <p className="text-gray-500 font-medium">Verify student tokens and manage product shelves.</p>
        </div>
        
        <button 
          onClick={onBack}
          className="flex items-center gap-2 bg-white/5 border border-white/10 px-6 py-3 rounded-2xl font-bold text-sm hover:bg-white/10 transition-all text-gray-300"
        >
          <ArrowLeft className="w-4 h-4" /> Back to Dashboard
        </button>
      </div>

      <div className="max-w-7xl mx-auto grid grid-cols-1 lg:grid-cols-2 gap-8">
        
        {/* LEFT COLUMN: ACTIVE ORDERS */}
        <div className="bg-white/5 border border-white/10 rounded-[2.5rem] p-8 backdrop-blur-md">
           <h2 className="text-2xl font-black mb-8 flex items-center gap-3 text-orange-400 uppercase tracking-tight">
             <Package className="w-6 h-6" /> Incoming Tokens
           </h2>
           
           <div className="space-y-4 max-h-[600px] overflow-y-auto custom-scrollbar pr-2">
             {orders.length === 0 ? (
               <div className="text-center py-20 bg-black/20 rounded-3xl border border-white/5 text-gray-500 font-medium">
                 No active orders pending.
               </div>
             ) : (
               orders.map(order => (
                 <div key={order.id} className="bg-black/40 p-6 rounded-3xl border border-white/5 flex justify-between items-center group hover:bg-white/5 transition-all">
                    <div>
                      <p className="text-[10px] text-gray-500 font-black uppercase mb-1">Token #{order.id.slice(-6).toUpperCase()}</p>
                      <p className="text-xl font-black text-white">{order.itemName}</p>
                      <p className="text-xs text-indigo-400 font-bold mt-1">Student: {order.customerName}</p>
                    </div>
                    <button 
                      onClick={() => completeOrder(order.id)} 
                      className="p-4 bg-green-500/10 text-green-500 hover:bg-green-500 hover:text-white rounded-2xl transition-all shadow-lg"
                      title="Mark as Served"
                    >
                      <CheckCircle className="w-6 h-6" />
                    </button>
                 </div>
               ))
             )}
           </div>
        </div>

        {/* RIGHT COLUMN: INVENTORY MANAGEMENT */}
        <div className="bg-white/5 border border-white/10 rounded-[2.5rem] p-8 backdrop-blur-md">
           <h2 className="text-2xl font-black mb-8 flex items-center gap-3 text-indigo-400 uppercase tracking-tight">
             <RefreshCcw className="w-6 h-6" /> Manage Shelves
           </h2>
           
           <div className="space-y-4">
             {inventory.length === 0 ? (
                <div className="text-center py-10 text-gray-500">
                  No items in inventory. Add them in Firestore first.
                </div>
             ) : (
               inventory.map(item => (
                 <div key={item.id} className="bg-black/40 p-5 rounded-3xl border border-white/5 flex justify-between items-center">
                    <div className="flex items-center gap-4">
                      <div className="text-3xl bg-white/5 p-3 rounded-2xl">{item.icon || '📦'}</div>
                      <div>
                        <p className="font-bold text-white text-lg">{item.name}</p>
                        <p className="text-xs text-gray-500 font-bold">Price: ₹{item.price}</p>
                      </div>
                    </div>
                    
                    <div className="flex items-center gap-3 bg-black/60 rounded-xl p-2 border border-white/10">
                       <span className="text-[10px] text-gray-500 font-bold uppercase pl-2">Stock</span>
                       <input 
                         type="number" 
                         defaultValue={item.stock}
                         onBlur={(e) => updateStock(item.id, e.target.value)}
                         className="w-16 bg-white/10 border border-white/10 rounded-lg p-2 text-center text-white font-bold outline-none focus:bg-indigo-500/20 focus:border-indigo-500/50 transition-all"
                       />
                    </div>
                 </div>
               ))
             )}
           </div>
        </div>

      </div>
    </div>
  );
}

export default CanteenAdmin;
